/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    using namespace reaction;

    // 1. Create a reactive variable for the sensor using reaction::var with initial value
    auto sensor = var(initialValue);

    // 2. Create two reactive variables to track recompute count and last processed value using reaction::var
    auto recomputeCount = var(0);
    auto lastProcessedValue = var(initialValue);

    // 3. Create a filter-triggered calculation using reaction::calc that:
    //    - Compares current value with last processed value to check if difference exceeds threshold
    //    - If threshold is exceeded, updates the recompute count and last processed value
    //    - Returns a status string indicating "HIGH" or "NORMAL" based on levelThreshold
    auto statusCalc = calc([&]() -> std::string {
        double currentValue = sensor();
        double lastValue = lastProcessedValue();

        // Check if difference exceeds threshold
        if (std::abs(currentValue - lastValue) > diffThreshold) {
            // Update recompute count and last processed value
            recomputeCount.value(recomputeCount() + 1);
            lastProcessedValue.value(currentValue);

            // Determine status based on levelThreshold
            if (currentValue > levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        } else {
            // No change - return previous status without updating counts
            return lastProcessedValue() > levelThreshold ? "HIGH" : "NORMAL";
        }
    });

    // 4. Apply a filter to the calculation using the filter method with a lambda that checks the difference
    statusCalc.filter([&](double current, double last) -> bool {
        return std::abs(current - last) > diffThreshold;
    }, sensor, lastProcessedValue);

    // 5. Update the sensor variable with the first value using the value method
    sensor.value(firstUpdate);

    // 6. Record the recompute count after first update by calling the calculation
    int firstCount = recomputeCount();

    // 7. Update the sensor variable with the second value using the value method
    sensor.value(secondUpdate);

    // 8. Record the recompute count after second update by calling the calculation again
    int secondCount = recomputeCount();

    // 9. Get the final status string by calling the calculation
    std::string finalStatus = statusCalc();

    // 10. Return a tuple containing the final status, first recompute count, and second recompute count
    return std::make_tuple(finalStatus, firstCount, secondCount);
}

}  // namespace test_reaction
```

