struct SharedMutexResult {
    bool trySharedWithoutSafety;
    bool tryUniqueWhileSharedWithoutSafety;
    bool trySharedWithSafety;
    bool tryUniqueWhileSharedWithSafety;
};

SharedMutexResult test_conditional_shared_mutex() {
    // 1. Get thread manager instance
    auto& threadManager = reaction::ThreadManager::getInstance();

    // 2. Reset thread manager state
    threadManager.resetForTesting();

    // 3. Create ConditionalSharedMutex instance
    reaction::ConditionalSharedMutex mutex;

    // 4. Attempt to acquire shared lock without safety
    bool sharedLockNoSafety = mutex.try_shared_lock_no_safety();
    // 5. Record result
    SharedMutexResult result{
        .trySharedWithoutSafety = sharedLockNoSafety,
        .tryUniqueWhileSharedWithoutSafety = false,
        .trySharedWithSafety = false,
        .tryUniqueWhileSharedWithSafety = false
    };

    // 6. Unlock shared lock if acquired
    if (sharedLockNoSafety) {
        mutex.unlock_shared();
    }

    // 7. Create ConditionalSharedLockGuard in a scope block
    {
        reaction::ConditionalSharedLockGuard<reaction::ConditionalSharedMutex> guard(mutex);

        // 8. Attempt to acquire unique lock while shared lock is held without safety
        bool uniqueLockNoSafety = mutex.try_unique_lock_no_safety();
        // 9. Record result
        result.tryUniqueWhileSharedWithoutSafety = uniqueLockNoSafety;

        // 10. Unlock unique lock if acquired
        if (uniqueLockNoSafety) {
            mutex.unlock();
        }
    } // 11. Exit guard scope (RAII automatically unlocks)

    // 12. Enable thread safety
    threadManager.enableThreadSafety();

    // 13. Attempt to acquire shared lock with safety
    bool sharedLockWithSafety = mutex.try_shared_lock();
    // 14. Record result
    result.trySharedWithSafety = sharedLockWithSafety;

    // 15. Unlock shared lock if acquired
