    }

    // 4. Check if all names are unique by comparing set size with original count
    bool allUnique = (reactSet.size() == 3);

    // 5. Return the ordering snapshot
    return OrderingSnapshot{orderedNames, allUnique};
}

}  // namespace test_reaction
